/bin/zsh -lc "python - <<'PY'
import csv, json
from decimal import Decimal, ROUND_HALF_UP
perf={'S':Decimal('3.0'),'A':Decimal('2.0'),'B':Decimal('1.0')}
def team(x):
    x=Decimal(x)
    if x>=Decimal('3.5'): return Decimal('1.2')
    if x>=Decimal('2.5'): return Decimal('1.0')
    return Decimal('0.8')
def seniority(x):
    x=Decimal(x)
    if x<1: return Decimal('0.5')
    if x<3: return Decimal('0.8')
    if x<5: return Decimal('1.0')
    if x<10: return Decimal('1.2')
    return Decimal('1.5')
res=[]
with open('input.csv', newline='') as f:
    for r in csv.DictReader(f):
        salary=Decimal(r['base_salary'])
        months=Decimal(r['months_worked'])
        if r['performance']=='C' or months < 6:
            bonus=0
        else:
            raw=salary*perf[r['performance']]*team(r['team_avg_score'])*seniority(r['seniority_years'])*(months/Decimal(12))
            final=min(raw, salary*4)
            bonus=int(final.quantize(Decimal('1'), rounding=ROUND_HALF_UP))
        res.append({'id': r['id'], 'bonus': bonus})
print(json.dumps(res, ensure_ascii=False))
print('matches', res == json.load(open('output.json')))
PY"

